package processlifecycle

import (
	"context"
	"fmt"
	"os"
	"path/filepath"
	"strings"
	"sync"
	"time"

	"irrlicht/core/domain/agent"
)

// DefaultInterval is the polling interval used when none is specified.
const DefaultInterval = 1 * time.Second

// BackoffInterval is the slower polling interval used when the PID set is stable.
const BackoffInterval = 5 * time.Second

// stableThreshold is the number of consecutive stable polls before backing off.
const stableThreshold = 5

// trackedProc holds the pre-session metadata for a running process.
type trackedProc struct {
	sessionID  string
	projectDir string
	superseded bool // real transcript exists; keep tracking to prevent re-creation
}

// Scanner polls for agent processes and emits synthetic EventNewSession /
// EventRemoved events so the session can be shown before the first message.
// It implements inbound.AgentWatcher.
type Scanner struct {
	processName  string        // exact process name matched by pgrep -x
	adapter      string        // adapter label placed on emitted events
	projectsRoot string        // absolute path to ~/.claude/projects (or equivalent)
	interval     time.Duration

	// sessionChecker is an optional function that reports whether any
	// non-proc session already exists for the given encoded projectDir.
	// When set, it is consulted before the file-modification-time fallback
	// in hasActiveSession so that idle (but alive) sessions suppress ghost
	// proc creation.
	sessionChecker func(projectDir string) bool

	mu      sync.Mutex
	tracked map[int]trackedProc // pid → pre-session
	subs    []chan agent.Event

	// Adaptive backoff: back off to BackoffInterval when PID set is stable.
	lastPIDCount int
	stablePolls  int
}

// NewScanner creates a Scanner for the given agent process.
//   - processName: exact binary name, e.g. "claude"
//   - adapter:     adapter label, e.g. "claude-code"
//   - projectsRoot: absolute path to the projects directory, e.g. ~/.claude/projects
//   - interval:    how often to poll; pass 0 to use DefaultInterval
func NewScanner(processName, adapter, projectsRoot string, interval time.Duration) *Scanner {
	if interval <= 0 {
		interval = DefaultInterval
	}
	return &Scanner{
		processName:  processName,
		adapter:      adapter,
		projectsRoot: projectsRoot,
		interval:     interval,
		tracked:      make(map[int]trackedProc),
	}
}

// WithSessionChecker sets a function that reports whether any non-proc session
// exists for the given encoded projectDir (e.g. "-Users-ingo-projects-foo").
// When set, hasActiveSession consults it before the file-modification fallback,
// preventing ghost proc sessions for directories with idle real sessions.
func (s *Scanner) WithSessionChecker(fn func(projectDir string) bool) *Scanner {
	s.sessionChecker = fn
	return s
}

// Watch begins polling. It runs an immediate scan then continues on the
// configured interval until ctx is cancelled. The interval backs off from
// DefaultInterval to BackoffInterval when the PID set is stable.
func (s *Scanner) Watch(ctx context.Context) error {
	s.poll()

	ticker := time.NewTicker(s.interval)
	defer ticker.Stop()
	currentInterval := s.interval

	for {
		select {
		case <-ctx.Done():
			return ctx.Err()
		case <-ticker.C:
			s.poll()

			// Adaptive backoff: count how many polls the PID set stayed the same.
			s.mu.Lock()
			pidCount := len(s.tracked)
			s.mu.Unlock()

			if pidCount == s.lastPIDCount {
				s.stablePolls++
			} else {
				s.stablePolls = 0
				s.lastPIDCount = pidCount
			}

			var targetInterval time.Duration
			if s.stablePolls >= stableThreshold {
				targetInterval = BackoffInterval
			} else {
				targetInterval = s.interval
			}
			if targetInterval != currentInterval {
				ticker.Reset(targetInterval)
				currentInterval = targetInterval
			}
		}
	}
}

// Subscribe returns a channel that receives agent events from this scanner.
func (s *Scanner) Subscribe() <-chan agent.Event {
	ch := make(chan agent.Event, 4)
	s.mu.Lock()
	s.subs = append(s.subs, ch)
	s.mu.Unlock()
	return ch
}

// Unsubscribe removes a previously subscribed channel and closes it.
func (s *Scanner) Unsubscribe(ch <-chan agent.Event) {
	s.mu.Lock()
	defer s.mu.Unlock()
	for i, c := range s.subs {
		if c == ch {
			s.subs = append(s.subs[:i], s.subs[i+1:]...)
			close(c)
			return
		}
	}
}

// poll runs one detection cycle: finds live processes, emits new-session events
// for newcomers without transcripts, and removes pre-sessions that have exited
// or whose real transcript has appeared.
func (s *Scanner) poll() {
	pids, err := FindProcesses(s.processName)
	if err != nil {
		return
	}

	live := make(map[int]bool, len(pids))
	for _, pid := range pids {
		live[pid] = true
	}

	// --- handle newly-seen PIDs ---
	for _, pid := range pids {
		s.mu.Lock()
		_, alreadyTracked := s.tracked[pid]
		s.mu.Unlock()

		cwd, err := ProcessCWD(pid)
		if err != nil || cwd == "" {
			continue
		}
		projectDir := CWDToProjectDir(cwd)

		if alreadyTracked {
			s.mu.Lock()
			proc := s.tracked[pid]
			s.mu.Unlock()

			// Already superseded — real transcript took over; nothing to do.
			if proc.superseded {
				continue
			}

			// Check whether a real transcript has appeared since we last looked.
			if s.hasActiveSession(projectDir) {
				// Mark as superseded and emit removal. Keep in tracked map
				// so we don't recreate the pre-session on the next poll.
				s.mu.Lock()
				proc.superseded = true
				s.tracked[pid] = proc
				s.mu.Unlock()
				s.broadcast(agent.Event{
					Type:       agent.EventRemoved,
					Adapter:    s.adapter,
					SessionID:  proc.sessionID,
					ProjectDir: projectDir,
				})
			}
			continue
		}

		// Skip if an active transcript was recently modified in this project
		// dir (the file watcher handles those). Old transcripts from previous
		// sessions are ignored so new processes are still detected.
		if s.hasActiveSession(projectDir) {
			continue
		}

		sessionID := fmt.Sprintf("proc-%d", pid)
		ev := agent.Event{
			Type:       agent.EventNewSession,
			Adapter:    s.adapter,
			SessionID:  sessionID,
			ProjectDir: projectDir,
			CWD:        cwd,
		}

		// Track the PID and emit atomically — but only if subscribers exist.
		// If no subscribers yet (startup race with SessionDetector.Run), skip
		// tracking so the next poll retries rather than silently losing the event.
		s.mu.Lock()
		if len(s.subs) > 0 {
			s.tracked[pid] = trackedProc{sessionID: sessionID, projectDir: projectDir}
			for _, ch := range s.subs {
				select {
				case ch <- ev:
				default:
				}
			}
		}
		s.mu.Unlock()
	}

	// --- handle exited PIDs ---
	s.mu.Lock()
	var exited []trackedProc
	for pid, proc := range s.tracked {
		if !live[pid] {
			exited = append(exited, proc)
			delete(s.tracked, pid)
		}
	}
	s.mu.Unlock()

	for _, proc := range exited {
		s.broadcast(agent.Event{
			Type:       agent.EventRemoved,
			Adapter:    s.adapter,
			SessionID:  proc.sessionID,
			ProjectDir: proc.projectDir,
		})
	}
}

// hasActiveSession returns true if the project directory has an active session.
// It first consults the injected sessionChecker (if set) to catch idle sessions
// whose transcripts haven't been written recently, then falls back to checking
// for a recently-modified .jsonl file (within 60 seconds).
func (s *Scanner) hasActiveSession(projectDir string) bool {
	if projectDir == "" {
		return false
	}
	if s.sessionChecker != nil && s.sessionChecker(projectDir) {
		return true
	}
	if s.projectsRoot == "" {
		return false
	}
	dir := filepath.Join(s.projectsRoot, projectDir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		return false
	}
	cutoff := time.Now().Add(-60 * time.Second)
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".jsonl") {
			continue
		}
		info, err := e.Info()
		if err != nil {
			continue
		}
		if info.ModTime().After(cutoff) {
			return true
		}
	}
	return false
}

// broadcast sends an event to all subscribers non-blocking (drops if full).
func (s *Scanner) broadcast(ev agent.Event) {
	s.mu.Lock()
	defer s.mu.Unlock()
	for _, ch := range s.subs {
		select {
		case ch <- ev:
		default:
		}
	}
}

// Process scanner: detects Claude Code processes before they create a
// transcript, so the session appears as ready from the moment the app opens.
procScanner := processlifecycle.NewScanner(
	"claude",
	claudecode.AdapterName,
	claudeCodeWatcher.Root(),
	0, // use default interval
)
// Suppress ghost proc sessions for directories that already have a real
// (transcript-backed) session, even if the transcript hasn't been written
// recently. Without this, idle sessions allow short-lived helper processes
// to create spurious proc-<pid> entries in the UI.
procScanner.WithSessionChecker(func(projectDir string) bool {
	sessions, err := cachedRepo.ListAll()
	if err != nil {
		return false
	}
	for _, s := range sessions {
		if strings.HasPrefix(s.SessionID, "proc-") {
			continue
		}
		if s.TranscriptPath != "" &&
			filepath.Base(filepath.Dir(s.TranscriptPath)) == projectDir {
			return true
		}
	}
	return false
})

watchers := []inbound.AgentWatcher{claudeCodeWatcher, codexWatcher, piWatcher, procScanner}

// Per-adapter PID discovery: Claude Code uses CWD-based matching,
// Codex/Pi use transcript file writer detection.
pidDiscovers := map[string]services.PIDDiscoverFunc{
	claudecode.AdapterName: claudecode.DiscoverPID,
	codex.AdapterName:      codex.DiscoverPID,
	pi.AdapterName:         pi.DiscoverPID,
}

// SessionDetector: orchestrates AgentWatchers + ProcessWatcher.
detector = services.NewSessionDetector(
	watchers, pwPort,
	cachedRepo, logger, gitResolver, metricsCollector, push,
	Version, cfg.ReadySessionTTL,
	pidDiscovers,
)
{
	detectorCtx, detectorCancel := context.WithCancel(context.Background())
	defer detectorCancel()
	logger.LogInfo("startup", "", fmt.Sprintf("watching Claude Code (%s), Codex (%s), Pi (%s)",

Model           string          `json:"model,omitempty"`
CWD             string          `json:"cwd,omitempty"`
TranscriptPath  string          `json:"transcript_path,omitempty"`
GitBranch       string          `json:"git_branch,omitempty"`
ProjectName     string          `json:"project_name,omitempty"`
FirstSeen       int64           `json:"first_seen"`
UpdatedAt       int64           `json:"updated_at"`
Confidence      string          `json:"confidence"`
EventCount      int             `json:"event_count"`
LastEvent       string          `json:"last_event"`
LastMatcher     string          `json:"last_matcher,omitempty"`
Metrics         *SessionMetrics `json:"metrics,omitempty"`

// PID of the Claude Code process that owns this session (set on SessionStart).
PID int `json:"pid,omitempty"`

// ParentSessionID links a subagent session to its spawning parent session.
// Derived from file path or heuristic matching in SessionDetector.
ParentSessionID string `json:"parent_session_id,omitempty"`

// Subagents holds the aggregate state of all child sessions.
// Nil when this session has no children.
Subagents *SubagentSummary `json:"subagents,omitempty"`

// DaemonVersion records which irrlichd version created this session,
// enabling future data migrations when the schema evolves.
DaemonVersion string `json:"daemon_version,omitempty"`

// Transcript monitoring for waiting-state recovery.
LastTranscriptSize int64  `json:"last_transcript_size,omitempty"`

