				default:
				}
			}
		}
		s.mu.Unlock()
	}

	// --- handle exited PIDs ---
	s.mu.Lock()
	var exited []trackedProc
	for pid, proc := range s.tracked {
		if !live[pid] {
			exited = append(exited, proc)
			delete(s.tracked, pid)
		}
	}
	s.mu.Unlock()

	for _, proc := range exited {
		s.broadcast(agent.Event{
			Type:       agent.EventRemoved,
			Adapter:    s.adapter,
			SessionID:  proc.sessionID,
			ProjectDir: proc.projectDir,
		})
	}
}

// hasActiveSession returns true if the project directory has an active session
// for the given PID. It first consults the injected sessionChecker (if set)
// to catch idle sessions whose transcripts haven't been written recently — the
// checker matches on BOTH projectDir and pid so historical sessions from prior
// daemon runs don't block pre-session creation. If the checker doesn't match
// (or isn't set) it falls back to a project-scoped check for a
// recently-modified .jsonl file (within 60 seconds) which catches freshly
// written transcripts before they've been persisted to the repo.
func (s *Scanner) hasActiveSession(projectDir string, pid int) bool {
	if projectDir == "" {
		return false
	}
	if s.sessionChecker != nil && s.sessionChecker(projectDir, pid) {
		return true
	}
	if s.projectsRoot == "" {
		return false
	}
	dir := filepath.Join(s.projectsRoot, projectDir)
	entries, err := os.ReadDir(dir)
	if err != nil {
		return false
	}
	cutoff := time.Now().Add(-60 * time.Second)
	for _, e := range entries {
		if e.IsDir() || !strings.HasSuffix(e.Name(), ".jsonl") {
			continue
		}
		info, err := e.Info()
		if err != nil {
			continue
		}
		if info.ModTime().After(cutoff) {
			return true
		}
	}
	return false
}

