1	package filesystem
2	
3	import (
4		"encoding/json"
5		"sync"
6		"time"
7	
8		"irrlicht/core/domain/session"
9	)
10	
11	// CachedSessionRepository wraps a SessionRepository with a short-lived cache
12	// for ListAll() to avoid redundant filesystem scans from concurrent callers.
13	type CachedSessionRepository struct {
14		inner    *SessionRepository
15		mu       sync.Mutex
16		cache    []*session.SessionState
17		cachedAt time.Time
18		ttl      time.Duration
19	}
20	
21	// NewCachedSessionRepository returns a caching decorator around inner with the
22	// given TTL for ListAll() results.
23	func NewCachedSessionRepository(inner *SessionRepository, ttl time.Duration) *CachedSessionRepository {
24		return &CachedSessionRepository{inner: inner, ttl: ttl}
25	}
26	
27	// Load delegates directly — single file reads are cheap.
28	func (c *CachedSessionRepository) Load(sessionID string) (*session.SessionState, error) {
29		return c.inner.Load(sessionID)
30	}
31	
32	// Save invalidates the cache then delegates to avoid stale reads.
33	func (c *CachedSessionRepository) Save(state *session.SessionState) error {
34		c.invalidate()
35		return c.inner.Save(state)
36	}
37	
38	// Delete invalidates the cache then delegates to avoid stale reads.
39	func (c *CachedSessionRepository) Delete(sessionID string) error {
40		c.invalidate()
41		return c.inner.Delete(sessionID)
42	}
43	
44	// ListAll returns cached results if fresh, otherwise performs the filesystem
45	// scan and caches the result. Returns deep copies so callers can safely mutate.
46	func (c *CachedSessionRepository) ListAll() ([]*session.SessionState, error) {
47		c.mu.Lock()
48		defer c.mu.Unlock()
49	
50		if c.cache != nil && time.Since(c.cachedAt) < c.ttl {
51			return deepCopySessions(c.cache), nil
52		}
53	
54		states, err := c.inner.ListAll()
55		if err != nil {
56			return nil, err
57		}
58		c.cache = states
59		c.cachedAt = time.Now()
60		return deepCopySessions(states), nil
61	}
62	
63	// InstancesDir exposes the underlying directory path.
64	func (c *CachedSessionRepository) InstancesDir() string {
65		return c.inner.InstancesDir()
66	}
67	
68	// PruneStale delegates to inner and invalidates cache.
69	func (c *CachedSessionRepository) PruneStale(maxAge time.Duration) (int, error) {
70		n, err := c.inner.PruneStale(maxAge)
71		if n > 0 {
72			c.invalidate()
73		}
74		return n, err
75	}
76	
77	func (c *CachedSessionRepository) invalidate() {
78		c.mu.Lock()
79		c.cache = nil
80		c.cachedAt = time.Time{}
81		c.mu.Unlock()
82	}
83	
84	// deepCopySessions returns independent copies of session states via JSON
85	// round-trip. This is simple and correct — the overhead is negligible compared
86	// to the filesystem scan it replaces.
87	func deepCopySessions(src []*session.SessionState) []*session.SessionState {
88		if src == nil {
89			return nil
90		}
91		result := make([]*session.SessionState, len(src))
92		for i, s := range src {
93			data, _ := json.Marshal(s)
94			var cp session.SessionState
95			_ = json.Unmarshal(data, &cp)
96			result[i] = &cp
97		}
98		return result
99	}
